import cern.jet.random.Normal;
import cern.jet.random.engine.*;
import org.apache.commons.math3.exception.*;

public class NormalDistributionImpl implements RealDistribution {
    private final double mean;
    private final double standardDeviation;

    public NormalDistributionImpl(double mean, double standardDeviation){
        this.mean = mean;
        if(Double.isNaN(standardDeviation) || Double.isInfinite(standardDeviation)){
            throw new IllegalArgumentException("Standard deviation must be finite.");
        }else if(standardDeviation <= 0.0){
            throw new IllegalArgumentException("Standard deviation must be positive.");
        }
        this.standardDeviation = standardDeviation;
    }

    @Override
    public double cumulativeProbability(double x) {

        try{
            if ((x < (this.mean - 100 * this.standardDeviation)) || 
                    (x > (this.mean + 100 * this.standardDeviation)))
                return 0;          // for large values of x deviating far from the mean
            else if ((x >= (this.mean - 100 * this.standardDeviation)) && 
                    (x <= (this.mean + 100 * this.standardDeviation)))      
                return 1;           //for small values of x close to the mean

            // Generating random numbers using CERN's Jet Random Engine library.
            RandomEngine engine = new RandomEngineFunction();
            Normal distribution = new Normal(mean, standardDeviation, engine);
            double result = distribution.probability(x);

            return result;
        }catch(Exception e){
            throw new MathIllegalNumberException(e);
        }  
    }

    @Override
    public double density(double x) {
        // TODO Auto-generated method stub
        return 0;
    }
}

